const input = $input.first().json;
const body = input.body ?? input;
const job = body.job ?? {};
const eventId = body.event?.id ?? body.eventId;
const jobId = job.id ?? body.jobId;
const callbackUrl = body.callbackUrl;
const callbackSecret = body.callbackSecret;
if (!jobId || !eventId || !callbackUrl) {
  return [];
}

const seedKeyword = job.seedKeyword ?? body.seedKeyword ?? 'Untitled topic';
const brief = job.brief ?? { title: seedKeyword, outline: [], angle: '', audience: '' };
const research = job.research ?? { objective: '', audience: '', gaps: [], sources: [] };
const sources = Array.isArray(research.sources) ? research.sources : [];
const outline = Array.isArray(brief.outline) && brief.outline.length
  ? brief.outline
  : ['คำตอบสั้นและภาพรวม', 'สิ่งที่ต้องเข้าใจก่อนลงมือ', 'ข้อมูลจากไทย', 'ข้อมูลจากต่างประเทศ', 'วิธีนำไปใช้จริง', 'คำถามที่คนค้นต่อ'];
const thaiSource = sources.find((source) => source.region === 'TH') ?? sources[0] ?? null;
const globalSource = sources.find((source) => source.region === 'Global') ?? sources[1] ?? sources[0] ?? null;

function bodyForSection(heading, index) {
  const gap = Array.isArray(research.gaps) && research.gaps.length ? research.gaps[index % research.gaps.length] : '';

  if (index === 0) {
    return [
      `${heading} ควรถูกเปิดด้วยคำตอบที่ตรงประเด็นก่อนว่าเรื่องนี้หมายถึงอะไร สำคัญต่อผู้อ่านอย่างไร และเหตุใดหลายคนจึงค้นคำว่า ${seedKeyword} ต่อเนื่องในหลายบริบท.`,
      `สิ่งที่ต้องเน้นคือ ${brief.angle || 'คำตอบเชิงใช้งานจริง'} โดยไม่สรุปแบบกว้างเกินไป แต่พาผู้อ่านเห็นทั้งภาพรวม เหตุผล และจุดที่ควรเช็กต่อทันที.`,
      thaiSource || globalSource
        ? `จากข้อมูลที่รวบรวมมา ${thaiSource ? `${thaiSource.title} ระบุว่า ${thaiSource.insight}` : ''} ${globalSource ? `${globalSource.title} ระบุว่า ${globalSource.insight}` : ''}`
        : `บทความช่วงเปิดควรยืนยันว่าคำตอบไม่ได้มาจากการคาดเดา แต่เกิดจากการสรุปใหม่จากหลายแหล่งข้อมูลจริง.`
    ].join('\n\n');
  }

  if (index === 1) {
    return [
      `ก่อนลงมือ ผู้อ่านควรเข้าใจก่อนว่า ${research.objective || `หัวข้อนี้เกี่ยวข้องกับ ${seedKeyword} โดยตรง`} ดังนั้น section นี้ต้องทำหน้าที่ปูพื้นฐานให้ชัด ไม่รีบกระโดดไปข้อสรุปสุดท้ายทันที.`,
      gap
        ? `จุดที่หลายบทความพลาดคือ ${gap} ถ้าไม่อธิบายส่วนนี้ให้ชัด บทความจะดูเหมือนแค่รวบคำตอบ แต่ไม่ช่วยให้คนอ่านตัดสินใจได้จริง.`
        : `สิ่งสำคัญคือทำให้คนอ่านเห็นว่าคำตอบของหัวข้อนี้ขึ้นกับบริบทและเงื่อนไข ไม่ใช่กฎตายตัวเพียงข้อเดียว.`,
      `รูปแบบการอธิบายที่เหมาะคือใช้ภาษาไทยที่ลื่น อ่านง่าย แต่ยังคงชื่อแหล่งหรือคำเทคนิคอังกฤษในจุดที่ช่วยเพิ่มความแม่นและความน่าเชื่อถือ.`
    ].join('\n\n');
  }

  if (index === 2) {
    return [
      `ถ้ามองจากฝั่งไทย จะเห็นรูปแบบคำถามและความเข้าใจของผู้ใช้ที่ชัดกว่าการอ่านนิยามเพียงอย่างเดียว.`,
      thaiSource
        ? `${thaiSource.title} จาก ${thaiSource.source} สะท้อนว่า ${thaiSource.insight}`
        : `ข้อมูลไทยควรถูกใช้เพื่อให้บทความตอบด้วยภาษาที่ผู้อ่านจริงคุ้นเคย ไม่ดูเป็นบทความแปลตรงตัว.`,
      `ดังนั้น section นี้ควรสรุปให้เห็นทั้ง wording ที่คนค้นจริงใช้ และสิ่งที่ผู้อ่านไทยควรระวังหรือควรทำต่อหลังอ่านจบ.`
    ].join('\n\n');
  }

  if (index === 3) {
    return [
      `เมื่อดูข้อมูลต่างประเทศ สิ่งที่ได้เพิ่มคือกรอบคิดที่เป็นระบบกว่าและคำอธิบายเชิงมาตรฐานที่ช่วยยืนยันเหตุผลของบทความ.`,
      globalSource
        ? `${globalSource.title} จาก ${globalSource.source} ชี้ว่า ${globalSource.insight}`
        : `แหล่งสากลมีประโยชน์ในฐานะ reference ที่ช่วยยกระดับความน่าเชื่อถือและความครบถ้วนของบทความ.`,
      `อย่างไรก็ตาม ข้อมูลสากลไม่ควรถูกยกมาทั้งหมดแบบตรงตัว แต่ต้องเลือกเฉพาะส่วนที่สอดคล้องกับบริบทผู้อ่านไทยแล้วเรียบเรียงใหม่ให้ลื่นและเป็นธรรมชาติ.`
    ].join('\n\n');
  }

  if (index === 4) {
    return [
      `หลังจากอธิบายภาพรวมและแหล่งอ้างอิงแล้ว บทความควรพาผู้อ่านไปสู่การใช้งานจริง เช่น ขั้นตอนเช็กเบื้องต้น วิธีลดความเสี่ยง หรือการตัดสินใจต่อยอดที่เหมาะกับบริบทของตนเอง.`,
      `หัวใจของส่วนนี้คือทำให้คนอ่านรู้ว่า หลังอ่านจบแล้วควรทำอะไรต่อ ไม่ว่าจะเป็นการตรวจสอบข้อมูลเพิ่มเติม การเปลี่ยนวิธีใช้งาน หรือการปรับขั้นตอนที่เกี่ยวข้องกับ ${seedKeyword}.`,
      `การสรุปเป็นลำดับขั้นพร้อมเหตุผลจะช่วยให้บทความดูมีน้ำหนักมากกว่าการให้ checklist สั้น ๆ และยังเพิ่มโอกาสให้เกิด conversion ต่อจากบทความได้ดีขึ้น.`
    ].join('\n\n');
  }

  return [
    `ช่วงท้ายของบทความควรเก็บคำถามที่คนมักค้นต่อ เพื่อช่วยปิดข้อสงสัยและครอบ long-tail keyword เพิ่มเติม.`,
    `คำถามเหล่านี้ควรต่อยอดจาก ${seedKeyword} และ ${brief.title} โดยหลีกเลี่ยง FAQ ที่กว้างเกินไปหรือไม่สัมพันธ์กับสิ่งที่ผู้อ่านกำลังตัดสินใจอยู่จริง.`,
    `เมื่อวาง FAQ ให้ตรง intent บทความจะดูครบทั้งในมุมผู้อ่านและมุม SEO และยังช่วยเชื่อม internal links ไปยังบทความรองหรือหน้าบริการที่เกี่ยวข้องได้เป็นธรรมชาติ.`
  ].join('\n\n');
}

const draft = {
  intro: [
    `${brief.title} เป็นคำถามที่ผู้อ่านจำนวนมากค้นหาเพราะต้องการคำตอบที่ชัด ใช้งานได้ และมีข้อมูลรองรับมากกว่าคำแนะนำสั้น ๆ ที่กระจายอยู่หลายแหล่ง.`,
    `บทความนี้จึงถอดจากรีเสิร์ชจริงทั้งฝั่งไทยและต่างประเทศ เพื่อช่วยให้ผู้อ่านเข้าใจภาพรวม เห็นจุดที่ต้องระวัง และรู้ว่าควรทำอะไรต่ออย่างเป็นลำดับ.`,
    `เป้าหมายไม่ใช่แค่ตอบว่าถูกหรือผิด แต่ทำให้เรื่อง ${seedKeyword} ถูกอธิบายแบบอ่านแล้วนำไปใช้ต่อได้จริง.`
  ].join('\n\n'),
  sections: outline.map((heading, index) => ({
    heading,
    body: bodyForSection(heading, index)
  })),
  conclusion: [
    `ถ้าสรุปให้สั้นที่สุด เรื่อง ${seedKeyword} ไม่ควรถูกอธิบายเพียงมุมเดียว แต่ต้องมองทั้งภาพรวม เหตุผล และผลต่อการใช้งานจริงของผู้อ่าน.`,
    `เมื่อบทความเรียงจากคำตอบสั้น ภาพรวม ข้อมูลไทย ข้อมูลต่างประเทศ ไปจนถึงขั้นตอนและ FAQ ผู้อ่านจะรู้สึกว่าข้อมูลครบและเชื่อถือได้มากกว่าบทความที่อาศัยสูตรเดิมซ้ำ ๆ.`,
    `ก่อนเผยแพร่ ควรตรวจความสอดคล้องของคำศัพท์ โทนภาษา และ internal links อีกครั้ง เพื่อให้บทความพร้อมทั้งในมุม SEO และมุมการใช้งานจริง.`
  ].join('\n\n')
};

const callbackResponse = await fetch(callbackUrl, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    ...(callbackSecret ? { 'x-callback-secret': callbackSecret } : {})
  },
  body: JSON.stringify({
    eventId,
    jobId,
    type: 'draft',
    status: 'succeeded',
    workflowRunId: $execution.id,
    message: 'Draft workflow completed in n8n poller.',
    stage: 'drafting',
    payload: { provider: 'n8n-poller', executionId: $execution.id },
    draft
  })
});

if (!callbackResponse.ok) {
  throw new Error(`Draft callback failed with status ${callbackResponse.status}`);
}

return [];
